cache = DiskCache(cache_dir="api_cache", default_ttl=300)


def cached_response(ttl=None, key_prefix=""):
    """Decorator to cache API endpoint responses."""

    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Build cache key from request details
            cache_key = f"{key_prefix}:{request.method}:{request.path}:{request.query_string.decode('utf-8')}"

            # Try to get cached response
            cached = cache.get(cache_key)
            if cached is not None:
                response = jsonify(cached)
                response.headers["X-Cache"] = "HIT"
                return response

            # Call the actual function
            result = f(*args, **kwargs)

            # Cache the result
            if isinstance(result, dict):
                cache.set(cache_key, result, ttl=ttl)
                response = jsonify(result)
                response.headers["X-Cache"] = "MISS"
                return response

            return result

        return decorated_function

    return decorator


